import { Button, Card, Container, Row, Text } from "@nextui-org/react";
import React from "react";

export default function HeaderSection() {
  return (
    <Container id="header-section">
      <Card css={{ $$cardColor: "$colors$primary" }}>
        <Card.Body>
          <Row justify="center" align="center">
            <Text h6 size={15} color="white" css={{ m: 0 }}>
              NextUI gives you the best developer experience with all the
              features you need for building beautiful and modern websites and
              applications.
            </Text>
          </Row>
        </Card.Body>
      </Card>
    </Container>
  );
}
